	return &MockBuildChecker{
		shouldFail: shouldFail,
	}
}

// CheckBuild performs a mock build check
func (m *MockBuildChecker) CheckBuild(ctx context.Context, config common.DeployConfig) (*common.DeployResult, error) {
	if m.shouldFail {
		return &common.DeployResult{
			Success: false,
			Message: "Mock build failed for testing",
		}, nil
	}

	return &common.DeployResult{
		Success:     true,
		Message:     "Mock build succeeded",
		Lane:        config.Lane,
		Environment: config.Environment,
		ImageURL:    "mock://test-image:latest",
	}, nil
}

